import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { fetchAssignedOrders } from "../../features/orders/orderSlice";
import { PackageCheck, Calendar, Truck, MapPin, BadgeCheck, Loader2, History, DollarSign, Clock } from "lucide-react";
import HeaderT from "./HeaderT";
import FooterB from "./FooterB";
import { useNavigate } from "react-router-dom";

const Dhistory = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { user } = useSelector((state) => state.auth);
  const deliveryPersonId = user?._id;
  const { orders, isLoading } = useSelector((state) => state.orders);

  useEffect(() => {
    if (!user) { navigate("/"); }
  }, [navigate, user]);

  useEffect(() => {
    if (deliveryPersonId) {
      dispatch(fetchAssignedOrders(deliveryPersonId));
    }
  }, [dispatch, deliveryPersonId]);

  const deliveredOrders = orders.filter((order) => order.orderStatus === "delivered");
  const nonCompletedDeliveries = orders?.filter((order) => order.orderStatus !== "delivered").length || 0;

  return (
    <div className="min-h-screen bg-[#f1f5f9] text-[#0f172a] font-['Inter',sans-serif]">
      <HeaderT />
      
      <main className="max-w-5xl mx-auto py-12 px-6">
        {/* Section Header */}
        <div className="flex flex-col items-center mb-12">
            <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mb-4 border border-slate-200 shadow-sm">
                <History className="w-8 h-8 text-teal-600" />
            </div>
            <h2 className="text-3xl font-black tracking-tight text-slate-900 uppercase">
               Mission <span className="text-teal-600">History</span>
            </h2>
            <p className="text-slate-400 font-bold uppercase tracking-[0.2em] text-[11px] mt-2">
               Comprehensive log of successful fulfillments
            </p>
        </div>

        {isLoading ? (
            <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[40px] border border-slate-200 shadow-sm">
               <Loader2 className="w-10 h-10 text-teal-500 animate-spin mb-4" />
               <p className="text-[11px] font-black uppercase tracking-widest text-slate-400">Syncing historical data...</p>
            </div>
        ) : deliveredOrders.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-[40px] border border-slate-200 shadow-sm">
               <PackageCheck className="w-12 h-12 text-slate-200 mx-auto mb-4" />
               <p className="text-[11px] font-black uppercase tracking-widest text-slate-400">No mission logs identified in the registry.</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 gap-4">
              {deliveredOrders.map((order) => (
                <div
                  key={order._id}
                  className="group bg-white border border-slate-200 rounded-[32px] p-8 hover:border-teal-500/30 transition-all shadow-sm hover:shadow-md"
                >
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 pb-8 border-b border-slate-100">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center border border-slate-100 group-hover:bg-teal-500 transition-colors group-hover:border-transparent">
                            <PackageCheck className="w-6 h-6 text-slate-400 group-hover:text-white transition-colors" />
                        </div>
                        <div>
                            <h4 className="text-slate-900 font-black text-lg leading-tight uppercase tracking-tight">
                               Order <span className="text-teal-600">#{order._id.slice(-6).toUpperCase()}</span>
                            </h4>
                            <div className="flex items-center gap-2 mt-1">
                                <Clock className="w-3 h-3 text-slate-400" />
                                <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">
                                    {new Date(order.updatedAt).toLocaleTimeString()} · {new Date(order.updatedAt).toLocaleDateString()}
                                </span>
                            </div>
                        </div>
                    </div>
                    <div>
                        <span className="px-5 py-2 bg-teal-50 border border-teal-100 text-teal-700 text-[10px] font-black rounded-full uppercase tracking-widest">
                           Status: Finalized
                        </span>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-6">
                        <div className="flex items-start gap-4">
                            <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center border border-slate-100 flex-shrink-0">
                                <MapPin className="w-5 h-5 text-teal-600" />
                            </div>
                            <div>
                                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 block mb-1">Target Coordinates</span>
                                <span className="text-slate-600 font-bold text-sm leading-relaxed">{order.address}, {order.city}</span>
                            </div>
                        </div>
                        <div className="flex items-start gap-4">
                            <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center border border-slate-100 flex-shrink-0">
                                <DollarSign className="w-5 h-5 text-teal-600" />
                            </div>
                            <div>
                                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 block mb-1">Transaction Value</span>
                                <span className="text-slate-900 font-black text-sm uppercase tracking-tight">{order.totalPrice.toLocaleString()} ETB</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex flex-col justify-end items-end">
                         <div className="flex items-center gap-3 py-3 px-6 bg-slate-50 border border-slate-100 rounded-2xl group-hover:border-teal-500/20 transition-all shadow-sm">
                            <BadgeCheck className="w-5 h-5 text-teal-600" />
                            <span className="text-[11px] font-black uppercase tracking-widest text-slate-400">Signature Verified</span>
                         </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
        )}
      </main>

      <FooterB assignedOrderCount={nonCompletedDeliveries} />
    </div>
  );
};

export default Dhistory;
