import React, { useRef, useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import Userdropdown from "./Userdropdown";
import Userdropdown2 from "./Userdropdown2";
import { useSelector } from "react-redux";
import { User, Bell, Menu, ShieldCheck, ChevronDown, Package } from "lucide-react";

function HeaderT() {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const userState = useSelector((state) => state?.auth);
  const dropdownRef = useRef(null);
  const navigate = useNavigate();

  // Handle scroll effect for premium glassmorphism
  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const toggleDropdown = () => setIsDropdownOpen(!isDropdownOpen);

  return (
    <header className={`sticky top-0 z-[100] transition-all duration-500 ${
      scrolled 
        ? "h-20 bg-white/90 backdrop-blur-xl border-b border-slate-200 shadow-lg" 
        : "h-24 bg-white border-b border-transparent"
    }`}>
      {/* Top Banner - Global Announcement */}
      <div className="bg-teal-500 h-1 hidden md:block w-full overflow-hidden">
        <div className="h-full bg-white/30 animate-pulse w-1/3" />
      </div>

      <div className="max-w-7xl mx-auto px-6 h-full flex items-center justify-between">
        {/* Left: Branding & Role */}
        <div className="flex items-center gap-6">
          <Link to="/delivery" className="flex items-center gap-4 group">
            <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center shadow-md border border-slate-100 group-hover:scale-105 transition-transform">
              <img
                src="/logo3.png"
                alt="Pulse Logo"
                className="w-8 h-8 object-contain"
              />
            </div>
            <div className="hidden sm:block">
              <h1 className="text-slate-900 font-black text-lg tracking-tight leading-none">
                PULSE<span className="text-teal-600">.</span>DELIVERY
              </h1>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-1.5">
                On-Route Protocol
              </p>
            </div>
          </Link>
        </div>

        {/* Center: System Status Indicator */}
        <div className="hidden lg:flex items-center gap-3 px-5 py-2.5 bg-slate-50 rounded-2xl border border-slate-100 shadow-inner">
           <div className="w-2 h-2 rounded-full bg-teal-500 animate-ping" />
           <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Signal Locked · GPS Active</span>
        </div>

        {/* Right: Actions & Profile */}
        <div className="flex items-center gap-4">
          <div className="relative" ref={dropdownRef}>
            <button 
              onClick={toggleDropdown}
              className="group flex items-center gap-3 p-1.5 pr-4 rounded-2xl bg-white border border-slate-200 hover:border-teal-500/50 hover:bg-slate-50 transition-all shadow-sm"
            >
              <div className="relative">
                <div className="w-10 h-10 rounded-xl bg-slate-100 flex items-center justify-center border border-slate-200 text-slate-500 group-hover:text-teal-600 transition-colors">
                  <User size={20} />
                </div>
                <div className="absolute -bottom-0.5 -right-0.5 w-3 h-3 bg-teal-500 rounded-full border-2 border-white shadow-sm" />
              </div>
              
              <div className="hidden md:flex flex-col items-start">
                <span className="text-[13px] font-black text-slate-900 leading-none group-hover:text-teal-600 transition-colors">
                  {userState?.user?.firstname || "Carrier"}
                </span>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">
                  Verified Agent
                </span>
              </div>
              <ChevronDown size={14} className={`text-slate-400 group-hover:text-slate-600 transition-transform ${isDropdownOpen ? 'rotate-180' : ''}`} />
            </button>

            {/* Premium Dropdown */}
            {isDropdownOpen && (
              <>
                <div className="fixed inset-0 z-40" onClick={() => setIsDropdownOpen(false)} />
                <div className="absolute right-0 mt-3 w-64 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="p-5 border-b border-slate-100 bg-slate-50/50">
                    <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-1">Authenticated Account</p>
                    <p className="text-slate-900 font-bold truncate">{userState?.user?.email}</p>
                  </div>
                  
                  <div className="p-2">
                    {userState?.user ? (
                      <Userdropdown />
                    ) : (
                      <Userdropdown2 />
                    )}
                  </div>
                  
                  <div className="p-4 bg-slate-50 border-t border-slate-100 text-center">
                    <button 
                      onClick={() => {
                        localStorage.clear();
                        window.location.reload();
                      }}
                      className="w-full py-2.5 rounded-xl bg-rose-50 hover:bg-rose-500 text-rose-500 hover:text-white text-[11px] font-black uppercase tracking-widest transition-all"
                    >
                      Terminate Session
                    </button>
                  </div>
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      <style>{`
        header { font-family: 'Inter', sans-serif; }
      `}</style>
    </header>
  );
}

export default HeaderT;
